at::Tensor standard_matrix_multiplication_impl_npu(const at::Tensor& A, const at::Tensor& B) {
    // Output shape [M, N] where A is [M, K] and B is [K, N]
    TORCH_CHECK(A.dim() == 2 && B.dim() == 2, "Inputs must be 2D tensors");
    TORCH_CHECK(A.size(1) == B.size(0), "Incompatible matmul dimensions: A[M,K] x B[K,N]");
    auto options = A.options();
    at::Tensor C = at::empty({A.size(0), B.size(1)}, options);
    EXEC_NPU_CMD(aclnnStandardMatrixMultiplicationCustom, A, B, C);
    return C;
}

TORCH_LIBRARY_IMPL(myops, PrivateUse1, m) {
    m.impl("standard_matrix_multiplication_custom", &standard_matrix_multiplication_impl_npu);
